  streamingText: string;
  tokensCount: number;
  /** For COMPLETED — full response, usage stats, latency. */
  response: string;
  tokensUsed: number;
  latencyMs: number;
  /** For FIRST_TOKEN_GENERATED — TTFT in ms (RN events.ts:76). */
