  deviceId: string;
  osName: string;
  osVersion: string;
  model: string;
  /** For *_FAILED. */
  error: string;
  /** For DEVICE_STATE_CHANGED — RN events.ts:264. */
  property: string;
  newValue: string;
  oldValue: string;
  /** For BATTERY_CHANGED / THERMAL_CHANGED / CONNECTIVITY_CHANGED. */
